arguments.command:
# Try using the structured logger API directly via a small C# script
# First, let's check if we can use the StructuredLogger NuGet package
cat > /tmp/analyze_binlog.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF

cat > /tmp/analyze_binlog.cs << 'CSHARP'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
var warnings = build.FindChildrenRecursive<Warning>().ToList();

Console.WriteLine($"=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine($"Total warnings: {warnings.Count}");
Console.WriteLine();

// Group errors by project
var errorsByProject = errors.GroupBy(e => {
    var node = (BaseNode)e;
    while (node != null) {
        if (node is Project p) return p.Name;
        node = node.Parent as BaseNode;
    }
    return "(unknown)";
}).OrderBy(g => g.Key);

foreach (var group in errorsByProject)
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var error in group)
    {
        var file = error.File ?? "";
        var line = error.LineNumber;
        var code = error.Code ?? "";
        Console.WriteLine($"  [{code}] {error.Text}");
        if (!string.IsNullOrEmpty(file))
            Console.WriteLine($"    File: {file}:{line}");
    }
    Console.WriteLine();
}

// Print warnings that might be relevant
var relevantWarnings = warnings.Where(w => 
    w.Code != null && (w.Code.StartsWith("NU") || w.Code.StartsWith("MSB"))).ToList();
if (relevantWarnings.Any())
{
    Console.WriteLine("=== RELEVANT WARNINGS ===");
    foreach (var w in relevantWarnings.Take(20))
    {
        Console.WriteLine($"  [{w.Code}] {w.Text}");
    }
}

// Show project dependency info - which projects depend on which
Console.WriteLine();
Console.WriteLine("=== PROJECT STRUCTURE ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var proj in projects.Where(p => p.FindChildrenRecursive<Error>().Any()))
{
    Console.WriteLine($"  {proj.Name} (has errors)");
    // Find ProjectReference items
    var projRefs = proj.FindChildrenRecursive<NamedNode>()
        .Where(n => n.Name == "ProjectReference" || (n is Item item && item.Name == "ProjectReference"))
        .ToList();
}
CSHARP

