# The StructuredLogger is extracting embedded source files from binlog 
# and MSBuild picks them up. Let me isolate the analyzer better.
mkdir -p /tmp/binlog_analyzer/src
cat > /tmp/binlog_analyzer/src/analyze_binlog.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <EnableDefaultCompileItems>false</EnableDefaultCompileItems>
  </PropertyGroup>
  <ItemGroup>
    <Compile Include="Program.cs" />
  </ItemGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF

cat > /tmp/binlog_analyzer/src/Program.cs << 'CSHARP'
using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine($"=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");
Console.WriteLine();

// Collect all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
Console.WriteLine($"Total error count: {errors.Count}");
Console.WriteLine();

// Deduplicate errors by code+text+file+line
var uniqueErrors = errors
    .Select(e => new {
        Code = e.Code ?? "",
        Text = e.Text ?? "",
        File = e.File ?? "",
        Line = e.LineNumber,
        ProjectPath = GetProjectPath(e)
    })
    .Distinct()
    .ToList();

Console.WriteLine($"Unique errors: {uniqueErrors.Count}");
Console.WriteLine();

// Group by project
var errorsByProject = uniqueErrors
    .GroupBy(e => e.ProjectPath)
    .OrderBy(g => g.Key);

foreach (var group in errorsByProject)
{
    Console.WriteLine($"━━━ Project: {group.Key} ━━━");
    foreach (var error in group.OrderBy(e => e.File).ThenBy(e => e.Line))
    {
        Console.WriteLine($"  [{error.Code}] {error.Text}");
        if (!string.IsNullOrEmpty(error.File))
            Console.WriteLine($"    at {error.File}:{error.Line}");
    }
    Console.WriteLine();
}

// Show project dependency structure
Console.WriteLine("=== PROJECT DEPENDENCY GRAPH ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
var projectsByName = projects.GroupBy(p => p.Name).Select(g => g.First()).ToList();

foreach (var proj in projectsByName)
{
    var childProjects = proj.FindChildrenRecursive<Project>().ToList();
    var hasErrors = proj.FindChildrenRecursive<Error>().Any();
    var marker = hasErrors ? " [FAILED]" : " [OK]";
    Console.WriteLine($"  {proj.Name}{marker}");
    foreach (var child in childProjects.GroupBy(c => c.Name).Select(g => g.First()))
    {
        Console.WriteLine($"    -> {child.Name}");
    }
}

// Show warnings (NuGet, MSBuild)
var warnings = build.FindChildrenRecursive<Warning>()
    .Where(w => w.Code != null && (w.Code.StartsWith("NU") || w.Code.StartsWith("MSB")))
    .Select(w => new { Code = w.Code, Text = w.Text })
    .Distinct()
    .ToList();

if (warnings.Any())
{
    Console.WriteLine();
    Console.WriteLine("=== RELEVANT WARNINGS ===");
    foreach (var w in warnings.Take(30))
    {
        Console.WriteLine($"  [{w.Code}] {w.Text}");
    }
}

static string GetProjectPath(BaseNode node)
{
    var current = node.Parent as BaseNode;
    while (current != null)
    {
        if (current is Project p) return p.Name ?? "(unknown)";
        current = current.Parent as BaseNode;
    }
    return "(unknown)";
}
