var build = BinaryLog.ReadBuild(binlogPath);

var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var proj in projects.GroupBy(p => p.Name).Select(g => g.First()))
{
    var hasErrors = proj.FindChildrenRecursive<Error>().Any();
    Console.WriteLine($"\n========== Project: {proj.Name} ({(hasErrors ? "FAILED" : "OK")}) ==========");
