using System;
using System.Reflection;
using Microsoft.Build.Logging.StructuredLogger;

// List all members of BinLogReader
var type = typeof(BinLogReader);
Console.WriteLine("=== BinLogReader members ===");
foreach (var m in type.GetMembers(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static))
    Console.WriteLine($"  [{m.MemberType}] {m.Name}");

Console.WriteLine("\n=== ArchiveFile type ===");
var afType = typeof(BinaryLog).Assembly.GetType("Microsoft.Build.Logging.StructuredLogger.ArchiveFile");
if (afType != null)
{
    foreach (var m in afType.GetMembers(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  [{m.MemberType}] {m.Name}");
}

Console.WriteLine("\n=== ArchiveFileEventArgs type ===");
var afeType = typeof(BinaryLog).Assembly.GetType("Microsoft.Build.Logging.StructuredLogger.ArchiveFileEventArgs");
if (afeType != null)
{
    foreach (var m in afeType.GetMembers(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  [{m.MemberType}] {m.Name}");
}

// Check for SourceFile type
Console.WriteLine("\n=== SourceFile type members ===");
var sfType = typeof(SourceFile);
foreach (var m in sfType.GetMembers(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  [{m.MemberType}] {m.Name}");

// Check build node for SourceFilesArchive children
var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);
Console.WriteLine("\n=== Direct children of Build ===");
if (build is TreeNode tn)
{
    foreach (var child in tn.Children)
        Console.WriteLine($"  [{child.GetType().Name}] {child}");
}

// Look for SourceFilesArchive in the tree
Console.WriteLine("\n=== All SourceFile nodes ===");
var sfs = build.FindChildrenRecursive<SourceFile>().ToList();
Console.WriteLine($"Found {sfs.Count} SourceFile nodes");
foreach (var sf in sfs.Take(10))
{
    Console.WriteLine($"  {sf.Name}");
    if (sf is TreeNode sftn)
    {
        foreach (var child in sftn.Children.Take(3))
            Console.WriteLine($"    [{child.GetType().Name}] {child.ToString()?.Substring(0, Math.Min(80, child.ToString()?.Length ?? 0))}");
    }
}
