cat > /tmp/binlog_analyzer/src/Program.cs << 'CSHARP'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get project evaluations
Console.WriteLine("=== PROJECT EVALUATIONS ===");
var evals = build.FindChildrenRecursive<ProjectEvaluation>().ToArray();
foreach (var eval in evals)
{
    Console.WriteLine($"\nProjectEvaluation: {eval.Name}");
    Console.WriteLine($"  ProjectFile: {eval.ProjectFile}");

    // Get items from evaluation
    var items = eval.FindChildrenRecursive<Item>().ToArray();
    var addItems = eval.FindChildrenRecursive<AddItem>().ToArray();

    // Look for PackageReference in AddItem groups
    foreach (var ai in addItems)
    {
        if (ai.Name == "PackageReference" || ai.Name == "ProjectReference")
        {
            Console.WriteLine($"  {ai.Name}:");
            foreach (var child in ai.Children)
            {
                if (child is Item item)
                {
                    var meta = item.FindChildrenRecursive<Metadata>().ToArray();
                    var version = meta.FirstOrDefault(m => m.Name == "Version")?.Value ?? "?";
                    Console.WriteLine($"    {item.Name} (Version: {version})");
                }
            }
        }
    }

    // Check for properties
    var tfm = eval.FindChildrenRecursive<Property>()
        .Where(p => p.Name == "TargetFramework")
        .Select(p => p.Value)
        .FirstOrDefault();
    if (tfm != null)
        Console.WriteLine($"  TargetFramework: {tfm}");
}

// Also look at the compilation command to see what references were passed
Console.WriteLine("\n\n=== CSC TASK PARAMETERS FOR FAILING PROJECT ===");
var cscTasks = build.FindChildrenRecursive<CscTask>().ToArray();
foreach (var csc in cscTasks)
{
    // Check if this is in the Services project
    BaseNode parent = csc;
    string projName = "";
    while (parent != null) {
        if (parent is Project p) { projName = p.Name; break; }
        parent = parent.Parent as BaseNode;
    }

    Console.WriteLine($"\nCsc in project: {projName}");

    // Get the source files parameter
    var sourceFiles = csc.FindChildrenRecursive<Item>()
        .Where(i => {
            var p = i.Parent;
            while (p != null) {
                if (p is Folder f && f.Name == "Sources") return true;
                if (p is Parameter param && param.Name == "Sources") return true;
                p = p.Parent;
            }
            return false;
        })
        .Select(i => i.Name)
        .Distinct()
        .ToArray();

    Console.WriteLine($"  Source files: {sourceFiles.Length}");
    foreach (var sf in sourceFiles)
        Console.WriteLine($"    {sf}");

    // Get reference assemblies
    var refs = csc.FindChildrenRecursive<Item>()
        .Where(i => {
            var p = i.Parent;
            while (p != null) {
                if (p is Parameter param && param.Name == "References") return true;
                p = p.Parent;
            }
            return false;
        })
        .Select(i => System.IO.Path.GetFileName(i.Name))
        .Distinct()
        .ToArray();

    Console.WriteLine($"  References: {refs.Length}");
    foreach (var r in refs)
        Console.WriteLine($"    {r}");

    // Check errors
    var errors = csc.FindChildrenRecursive<Error>().ToArray();
    if (errors.Length > 0)
    {
        Console.WriteLine($"  ERRORS:");
        foreach (var e in errors)
            Console.WriteLine($"    [{e.Code}] {e.Text} at {e.File}:{e.LineNumber}");
    }
}
